// Multiplies physical cash with digital footprint tokens
public class HybridCurrencySystem : MonoBehaviour {
  public float physicalSeedCredits = 100f;
  public float footprintScore = 0f; // Earned via persistence (academy tasks, droid redirection, terraforming actions)
  public float multiplier = 1f; // Scales 5x–150x like Jobs’ 150 calls
  public void ApplyFootprintMultiplier() {
    multiplier = 1f + (footprintScore / 100f);
    float effectiveValue = physicalSeedCredits * multiplier;
    Debug.Log($"Physical $ {physicalSeedCredits} now worth ${effectiveValue} via footprint tokens");
  }
}

